// Loop over input items
for (const item of $input.all()) {

  // Get the email string from the 'answer' field and trim whitespace
  const emailString = item.json.answer ? item.json.answer.trim() : null;

  // Initialize new fields
  item.json.isValidEmail = false;
  item.json.validationError = null;

  // 1. Check if input exists
  if (!emailString) {
    item.json.validationError = "Input field 'answer' is missing or empty.";
    continue; // Skip to the next item
  }

  // 2. Check for a valid email format using a robust regex
  // This regex is widely used (based on RFC 5322) and covers most
  // valid email formats, including less common ones.
  const regex = /^(([^<>()[\]\\.,;:\s@"]+(\.[^<>()[\]\\.,;:\s@"]+)*)|(".+"))@((\[[0-9]{1,3}\.[0-9]{1,3}\.[0-9]{1,3}\.[0-9]{1,3}\])|(([a-zA-Z\-0-9]+\.)+[a-zA-Z]{2,}))$/;

  if (!regex.test(emailString)) {
    item.json.validationError = "Invalid email format.";
    continue; // Skip to the next item
  }

  // 3. If all checks pass, mark as valid
  // If it passed the regex, it's a validly formatted email.
  item.json.isValidEmail = true;

}

return $input.all();

// Loop por todos os itens que entram no nó
for (const item of $input.all()) {
  let data;

  // 1. Tenta extrair o objeto de dentro da string 'json_resultado'
  try {
    // Se json_resultado já for objeto, ele usa direto. Se for string, faz o parse.
    data = (typeof item.json.json_resultado === 'string') 
           ? JSON.parse(item.json.json_resultado) 
           : item.json.json_resultado;
  } catch (e) {
    data = {};
  }

  // 2. Busca o valor do CEP (está na chave 'input' dentro do JSON)
  const rawAnswer = data.input || "";
  // Remove tudo que não for número (limpeza preventiva)
  const cepString = String(rawAnswer).replace(/\D/g, ""); 

  // 3. Inicializa as variáveis de saída no item
  item.json.isValidCep = false;
  item.json.validationError = null;
  item.json.formattedCep = null;

  // 4. REGEX CORRIGIDA: \d{8} verifica se existem exatamente 8 dígitos numéricos
  const cepRegex = /^\d{8}$/;
  const isValid = cepRegex.test(cepString);

  if (isValid) {
    item.json.isValidCep = true;
    // Formata para o padrão 00000-000
    item.json.formattedCep = cepString.replace(/(\d{5})(\d{3})/, "$1-$2");
  } else {
    item.json.isValidCep = false;
    item.json.validationError = "CEP Inválido ou mal formatado";
  }
}

// Retorna os itens processados
return $input.all();

